$file = "c:\Users\eaguilarher2\Documents\Antigravity\kof-sap-dashboard\dashboard_data.json"
$data = Get-Content -Raw $file -Encoding UTF8 | ConvertFrom-Json

foreach ($item in $data.value) {
    if ($updates.ContainsKey([string]$item.id)) {
        $item.currentWeek = $updates[[string]$item.id].c
        $item.prevWeek = $updates[[string]$item.id].p
        
        # Determine status
        if ($item.currentWeek -match "Sin incidente") {
            $item.status = "Sin Incidentes"
        } elseif ($item.currentWeek -match "(?i)(Indisponibilidad|Afectación|Incidente|problema)") {
            $item.status = "Con Incidentes"
        } else {
            $item.status = "En Proceso"
        }
    }
}

$data | ConvertTo-Json -Depth 10 | Set-Content $file -Encoding UTF8

Write-Host "Update done."
